import { Report, Stats, Rollup } from '../types';

const API_BASE = '/api';

export const reportsApi = {
  // Get all reports with optional filtering
  getReports: async (params?: { month?: string; limit?: number; offset?: number }): Promise<Report[]> => {
    const searchParams = new URLSearchParams();
    if (params?.month) searchParams.append('month', params.month);
    if (params?.limit) searchParams.append('limit', params.limit.toString());
    if (params?.offset) searchParams.append('offset', params.offset.toString());
    
    const response = await fetch(`${API_BASE}/reports?${searchParams}`);
    if (!response.ok) throw new Error('Failed to fetch reports');
    return response.json();
  },

  // Create or update a report
  createReport: async (data: {
    report_date: string;
    month_label?: string;
    data: Record<string, any>;
  }): Promise<Report> => {
    const response = await fetch(`${API_BASE}/reports`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error('Failed to create report');
    return response.json();
  },

  // Get dashboard statistics
  getStats: async (): Promise<Stats> => {
    const response = await fetch(`${API_BASE}/reports/stats`);
    if (!response.ok) throw new Error('Failed to fetch stats');
    return response.json();
  },

  // Get rollup data for charts
  getRollups: async (group: string = 'month'): Promise<Rollup[]> => {
    const response = await fetch(`${API_BASE}/reports/rollups?group=${group}`);
    if (!response.ok) throw new Error('Failed to fetch rollups');
    return response.json();
  },

  // Clear all data
  clearAll: async (): Promise<void> => {
    const response = await fetch(`${API_BASE}/reports`, {
      method: 'DELETE',
    });
    if (!response.ok) throw new Error('Failed to clear data');
  },
};
